ws for GameDetailViewstruct GameDetailHeaderCard: View {    let game: Game        var body: some View {        VStack(spacing: 20) {                        GameStatusView(game: game, textColor: .white.opacity(0.9))                        // Score Display            HStack(spacing: 40) {                TeamScoreView(                    teamName: game.awayTeam,                    score: game.awayScore,                    logoURL: game.awayLogoURL,                    sport: game.sport                )                                Text("VS")                    .font(.system(size: 14, weight: .medium))                    .foregroundColor(.white.opacity(0.7))                                TeamScoreView(                    teamName: game.homeTeam,                    score: game.homeScore,                    logoURL: game.homeLogoURL,                    sport: game.sport                )            }        }        .padding(.vertical, 30)        .frame(maxWidth: .infinity)        .background(            LinearGradient(                gradient: Gradient(colors: [                    game.sport.color,                    game.sport.color.opacity(0.7)                ]),                startPoint: .topLeading,                endPoint: .bottomTrailing            )        )        .cornerRadius(20)    }}struct TeamScoreView: View {    let teamName: String    let score: Int    let logoURL: String?    let sport: Sport        var body: some View {        VStack(spacing: 8) {            // Team Logo or Sport Icon            if let logoURL = logoURL, let url = URL(string: logoURL) {                AsyncImage(url: url) { image in                    image                        .resizable()                        .aspectRatio(contentMode: .fit)                } placeholder: {                    Image(systemName: sport.icon)                        .font(.system(size: 40))                        .foregroundColor(.white.opacity(0.9))                }                .frame(width: 50, height: 50)            } else {                Image(systemName: sport.icon)                    .font(.system(size: 40))                    .foregroundColor(.white.opacity(0.9))            }                        Text(teamName)                .font(.system(size: 16, weight: .medium))                .foregroundColor(.white)                .multilineTextAlignment(.center)                        Text("\(score)")                .font(.system(size: 36, weight: .bold))                .foregroundColor(.white)        }        .frame(width: 100)    }}struct FavoriteButtonsView: View {    let game: Game    @Environment(GamesViewModel.self) var viewModel        var body: some View {        HStack(spacing: 16) {            FavoriteButton(                teamName: game.awayTeam,                isFavorite: viewModel.isFavorite(game.awayTeam)            ) {                viewModel.toggleFavorite(game.awayTeam)            }                        FavoriteButton(                teamName: game.homeTeam,                isFavorite: viewModel.isFavorite(game.homeTeam)            ) {                viewModel.toggleFavorite(game.homeTeam)            }        }    }}struct FavoriteButton: View {    let teamName: String    let isFavorite: Bool    let action: () -> Void        var body: some View {        Button(action: action) {            Label(                isFavorite ? "Favorited" : "Favorite \(teamName)",                systemImage: isFavorite ? "star.fill" : "star"            )            .font(.system(size: 14, weight: .medium))        }        .buttonStyle(.borderedProminent)        .tint(isFavorite ? .yellow : .blue)    }}struct GameStatisticsView: View {    let game: Game    let stats: [GameStatistic]    let isLoading: Bool        var body: some View {        VStack(alignment: .leading, spacing: 16) {            Text("Game Statistics")                .font(.system(size: 18, weight: .bold))                .padding(.horizontal, 4)                        if isLoading {                // Loading state                VStack(spacing: 12) {                    ProgressView()                    Text("Loading stats...")                        .font(.system(size: 14))                        .foregroundColor(.secondary)                }                .frame(maxWidth: .infinity)                .padding(.vertical, 30)                .background(Color.white)                .cornerRadius(12)                .shadow(color: .black.opacity(0.05), radius: 3)            } else if stats.isEmpty {                // No stats available                VStack(spacing: 8) {                    Image(systemName: "chart.bar.xaxis")                        .font(.system(size: 30))                        .foregroundColor(.secondary)                    Text("Statistics not available")                        .font(.system(size: 14))                        .foregroundColor(.secondary)                }                .frame(maxWidth: .infinity)                .padding(.vertical, 30)                .background(Color.white)                .cornerRadius(12)                .shadow(color: .black.opacity(0.05), radius: 3)            } else {                VStack(spacing: 12) {                    ForEach(stats) { stat in                        StatRow(                            statName: stat.name,                            awayValue: stat.awayValue,                            homeValue: stat.homeValue,                            awayTeam: game.awayTeam,                            homeTeam: game.homeTeam                        )                    }                }                .padding()                .background(Color.white)                .cornerRadius(12)                .shadow(color: .black.opacity(0.05), radius: 3)            }        }    }}struct StatRow: View {    let statName: String    let awayValue: String    let homeValue: String    let awayTeam: String    let homeTeam: String        var body: some View {        VStack(spacing: 8) {            // Stat type            Text(statName)                .font(.system(size: 13, weight: .medium))                .foregroundColor(.secondary)                                    HStack {                // Away team value                Text(awayValue)                    .font(.system(size: 15, weight: .semibold))                    .frame(maxWidth: .infinity, alignment: .trailing)                                // Divider                Rectangle()                    .fill(Color.gray.opacity(0.3))                    .frame(width: 1, height: 20)                    .padding(.horizontal, 12)                                // Home team value                Text(homeValue)                    .font(.system(size: 15, weight: .semibold))                    .frame(maxWidth: .infinity, alignment: .leading)            }        }        .padding(.vertical, 4)    }}struct GameStatusView: View {    let game: Game    let textColor: Color        var body: some View {        HStack {            if case .live = game.status {                HStack(spacing: 4) {                    Circle()                        .fill(Color.red)                        .frame(width: 10, height: 10)                    Text("LIVE")                        .font(.system(size: 14, weight: .bold))                }                .foregroundColor(.red)            } else if case .final = game.status {                Text("FINAL")                    .font(.system(size: 14, weight: .bold))                    .foregroundColor(textColor)            }                        if let quarter = game.quarter {                Text(quarter)                    .font(.system(size: 14, weight: .medium))                    .foregroundColor(textColor)            }                        if let time = game.timeRemaining {                Text("• \(time)")                    .font(.system(size: 14, weight: .medium))                    .foregroundColor(textColor)            }        }    }}